import { useAlert } from '@/context/AlertContext';
import { useBottomTabBarHeight } from "expo-router/js-tabs";
import { useMutation, useQueryClient } from '@tanstack/react-query';
import Ionicons from '@expo/vector-icons/Ionicons';
import { router } from 'expo-router';
import { createStaff, updateStaffPermissions } from '@/services/staff';
import { Input } from '@/components/ui/Input';
import { Button } from '@/components/ui/Button';
import { useStaffDraftStore } from '@/store/staffDraftStore';
import { Colors } from '@/constants/Colors';
import { Typography } from '@/constants/Typography';
import { Spacing } from '@/constants/Spacing';
import { BorderRadius } from '@/constants/BorderRadius';

const DEFAULT_STAFF_PERMISSIONS = ['view_products', 'record_sale', 'view_sales'];

export default function NewStaffScreen() {
  const queryClient = useQueryClient();
  const tabBarHeight = useBottomTabBarHeight();
  const { permissions, setPermissions, reset } = useStaffDraftStore();
  const [form, setForm] = useState({ name: '', email: '', password: '', phone: '' });
  const { toast } = useAlert();

  useEffect(() => {
    setPermissions(DEFAULT_STAFF_PERMISSIONS);
    return () => reset();
  }, []);

  const saveMutation = useMutation({
    mutationFn: async () => {
      const created = await createStaff({
        name: form.name,
        email: form.email,
        password: form.password,
        phone: form.phone || undefined,
      });
      const staffId = created.data._id;
      await updateStaffPermissions(staffId, permissions);
      return created;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['staff'] });
      router.back();
    },
    onError: (error: any) => {
      toast({ type: 'error', message: error.response?.data?.message || 'Failed to add staff' });
    },
  });

  const handleSave = () => {
    if (!form.name || !form.email) {
      return toast({ type: 'error', message: 'Name and email are required' });
    }
    if (!form.password || form.password.length < 6) {
      return toast({ type: 'error', message: 'Password must be at least 6 characters' });
    }
    saveMutation.mutate();
  };

  return (
    <KeyboardAvoidingView style={styles.flex} behavior={Platform.OS === 'ios' ? 'padding' : 'height'}>
      <ScrollView
        showsVerticalScrollIndicator={false}
        contentContainerStyle={[styles.content, { paddingBottom: tabBarHeight + Spacing.lg }]}
        keyboardShouldPersistTaps="handled"
      >
        <View style={styles.section}>
          <Text style={styles.sectionLabel}>BASIC INFORMATION</Text>
          <Input label="Full Name" value={form.name} onChangeText={(t) => setForm({ ...form, name: t })} />
          <Input label="Email" value={form.email} onChangeText={(t) => setForm({ ...form, email: t })} autoCapitalize="none" keyboardType="email-address" />
          <Input label="Phone (optional)" value={form.phone} onChangeText={(t) => setForm({ ...form, phone: t })} keyboardType="phone-pad" />
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionLabel}>ACCOUNT</Text>
          <Input label="Password" value={form.password} onChangeText={(t) => setForm({ ...form, password: t })} secureTextEntry />
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionLabel}>ACCESS</Text>
          <AnimatedPressable style={styles.permissionsRow} onPress={() => router.push('/(owner)/staff/permissions')}>
            <View style={styles.permissionsIcon}>
              <Ionicons name="shield-checkmark-outline" size={20} color={Colors.primary} />
            </View>
            <View style={styles.permissionsText}>
              <Text style={styles.permissionsLabel}>Permissions</Text>
              <Text style={styles.permissionsCount}>{permissions.length} permission{permissions.length !== 1 ? 's' : ''} selected</Text>
            </View>
            <Ionicons name="chevron-forward" size={20} color={Colors.textTertiary} />
          </AnimatedPressable>
        </View>

        <Button title="Add Staff Member" onPress={handleSave} loading={saveMutation.isPending} style={styles.button} />
      </ScrollView>
    </KeyboardAvoidingView>
  );
}

const styles = StyleSheet.create({
  flex: { flex: 1, backgroundColor: Colors.background },
  content: { padding: Spacing.lg },
  section: { marginBottom: Spacing.lg },
  sectionLabel: {
    fontSize: Typography.size.caption,
    fontFamily: Typography.fontFamilySemiBold,
    color: Colors.textTertiary,
    letterSpacing: 0.8,
    marginBottom: Spacing.sm,
  },
  permissionsRow: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: Colors.surface,
    borderRadius: BorderRadius.md,
    borderWidth: 1,
    borderColor: Colors.border,
    padding: Spacing.md,
    gap: Spacing.md,
  },
  permissionsIcon: {
    width: 36,
    height: 36,
    borderRadius: 18,
    backgroundColor: Colors.primarySubtle,
    alignItems: 'center',
    justifyContent: 'center',
  },
  permissionsText: { flex: 1 },
  permissionsLabel: {
    fontSize: Typography.size.body,
    fontFamily: Typography.fontFamilySemiBold,
    color: Colors.textPrimary,
  },
  permissionsCount: { fontSize: Typography.size.small, color: Colors.textSecondary, marginTop: 2 },
  button: { marginTop: Spacing.sm },
});

import React, { useEffect } from 'react';
import { AnimatedPressable } from '@/components/ui/AnimatedPressable';
import { haptics } from '@/utils/haptics';
import {
  View,
  Text,
  StyleSheet,
  Platform,
  Dimensions,
} from 'react-native';
import { Tabs, Redirect } from 'expo-router';
import Ionicons from '@expo/vector-icons/Ionicons';
import { BlurView } from 'expo-blur';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
} from 'react-native-reanimated';
import { useAuth } from '@/context/AuthContext';
import { useCartStore } from '@/store/staffCartStore';
import { Typography } from '@/constants/Typography';
import { Colors } from '@/constants/Colors';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

interface TabConfig {
  name: string;
  label: string;
  icon: keyof typeof Ionicons.glyphMap;
  activeIcon: keyof typeof Ionicons.glyphMap;
}

const TAB_CONFIGS: TabConfig[] = [
  { name: 'dashboard', label: 'Home',  icon: 'home-outline',   activeIcon: 'home' },
  { name: 'inventory', label: 'Stock', icon: 'cube-outline',   activeIcon: 'cube' },
  { name: 'sales',     label: 'Sales', icon: 'cart-outline',   activeIcon: 'cart' },
  { name: 'profile',   label: 'Me',    icon: 'person-outline', activeIcon: 'person' },
];

const TAB_COUNT = TAB_CONFIGS.length;
const TAB_WIDTH = SCREEN_WIDTH / TAB_COUNT;

interface AnimatedTabIconProps {
  config: TabConfig;
  isFocused: boolean;
  cartCount: number;
}

const AnimatedTabIcon: React.FC<AnimatedTabIconProps> = ({ config, isFocused, cartCount }) => {
  const scale = useSharedValue(isFocused ? 1.1 : 0.95);
  const translateY = useSharedValue(isFocused ? -2 : 0);

  useEffect(() => {
    scale.value = withSpring(isFocused ? 1.1 : 0.95, { damping: 14, stiffness: 160 });
    translateY.value = withSpring(isFocused ? -2 : 0, { damping: 14, stiffness: 160 });
  }, [isFocused, scale, translateY]);

  const iconStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }, { translateY: translateY.value }],
  }));

  const showBadge = config.name === 'sales' && cartCount > 0;

  return (
    <Animated.View style={[iconStyle, { position: 'relative' }]}>
      <Ionicons
        name={isFocused ? config.activeIcon : config.icon}
        size={22}
        color={isFocused ? Colors.primary : '#94A3B8'}
      />
      {showBadge && (
        <View style={badgeStyles.dot}>
          <Text style={badgeStyles.text}>{cartCount > 9 ? '9+' : String(cartCount)}</Text>
        </View>
      )}
    </Animated.View>
  );
};

const badgeStyles = StyleSheet.create({
  dot: {
    position: 'absolute',
    top: -5,
    right: -8,
    minWidth: 16,
    height: 16,
    borderRadius: 8,
    backgroundColor: Colors.danger,
    alignItems: 'center',
    justifyContent: 'center',
    paddingHorizontal: 3,
    borderWidth: 1.5,
    borderColor: '#FFFFFF',
  },
  text: {
    fontSize: 9,
    fontFamily: Typography.fontFamilyBold,
    color: '#FFFFFF',
    lineHeight: 12,
  },
});

interface PremiumTabBarProps {
  state: {
    routes: Array<{ key: string; name: string }>;
    index: number;
  };
  descriptors: Record<string, { options: { title?: string; href?: null } }>;
  navigation: {
    emit: (event: { type: string; target: string; canPreventDefault: boolean }) => { defaultPrevented: boolean };
    navigate: (args: { name: string; merge: boolean }) => void;
  };
}

const PremiumTabBar: React.FC<PremiumTabBarProps> = ({ state, descriptors, navigation }) => {
  const insets = useSafeAreaInsets();
  const cartCount = useCartStore((s) => s.cart.reduce((sum, i) => sum + i.cartQuantity, 0));

  const visibleRoutes = state.routes.filter((route) =>
    TAB_CONFIGS.some((tc) => tc.name === route.name),
  );

  const activeRoute = state.routes[state.index];
  const activeVisibleIndex = visibleRoutes.findIndex((r) => r.name === activeRoute?.name);

  const indicatorX = useSharedValue(activeVisibleIndex >= 0 ? activeVisibleIndex * TAB_WIDTH : 0);

  useEffect(() => {
    if (activeVisibleIndex >= 0) {
      indicatorX.value = withSpring(activeVisibleIndex * TAB_WIDTH, {
        damping: 20,
        stiffness: 200,
        mass: 0.8,
      });
    }
  }, [activeVisibleIndex, indicatorX]);

  const indicatorStyle = useAnimatedStyle(() => ({
    transform: [{ translateX: indicatorX.value }],
  }));

  const tabBarHeight = 58 + insets.bottom;

  return (
    <View style={[styles.tabBar, { height: tabBarHeight }]}>
      {Platform.OS === 'ios' ? (
        <BlurView intensity={85} tint="light" style={[StyleSheet.absoluteFill, styles.blurBase]} />
      ) : (
        <View style={[StyleSheet.absoluteFill, styles.androidBase]} />
      )}

      <View style={styles.topBorderLine} />

      <Animated.View style={[styles.pillContainer, indicatorStyle, { pointerEvents: 'none' }]}>
        <View style={styles.pill} />
      </Animated.View>

      <View style={[styles.tabsRow, { paddingBottom: insets.bottom }]}>
        {visibleRoutes.map((route) => {
          const config = TAB_CONFIGS.find((tc) => tc.name === route.name)!;
          const isFocused = route.name === activeRoute?.name;

          const onPress = () => {
            const event = navigation.emit({
              type: 'tabPress',
              target: route.key,
              canPreventDefault: true,
            });
            if (!isFocused && !event.defaultPrevented) {
              haptics.light();
              navigation.navigate({ name: route.name, merge: true });
            }
          };

          return (
            <AnimatedPressable
              key={route.key}
              onPress={onPress}
              style={styles.tabItem}
              accessibilityRole="button"
              accessibilityState={isFocused ? { selected: true } : {}}
              accessibilityLabel={config.label}
            >
              <AnimatedTabIcon config={config} isFocused={isFocused} cartCount={cartCount} />
              <Text
                style={[
                  styles.tabLabel,
                  { color: isFocused ? Colors.primary : '#94A3B8' },
                  isFocused && styles.tabLabelActive,
                ]}
              >
                {config.label}
              </Text>
            </AnimatedPressable>
          );
        })}
      </View>
    </View>
  );
};

export default function StaffLayout() {
  const { user, isLoading } = useAuth();

  if (!isLoading && (!user || user.role !== 'staff')) {
    return <Redirect href="/(auth)/login" />;
  }

  return (
    <Tabs
      tabBar={(props) => <PremiumTabBar {...(props as unknown as PremiumTabBarProps)} />}
      screenOptions={{
        headerShown: true,
        headerStyle: { backgroundColor: '#FFFFFF' },
        headerTintColor: '#0F172A',
        headerTitleStyle: {
          fontFamily: Typography.fontFamilySemiBold,
          fontSize: 16,
        },
        headerShadowVisible: false,
      }}
    >
      <Tabs.Screen name="dashboard" options={{ title: 'Smart Duka', headerShown: false }} />
      <Tabs.Screen name="inventory" options={{ title: 'Stock', headerShown: false }} />
      <Tabs.Screen name="sales"     options={{ title: 'Sales',  headerShown: false }} />
      <Tabs.Screen name="profile"   options={{ title: 'Profile' }} />
      <Tabs.Screen name="expenses"  options={{ title: 'Expenses', href: null }} />
    </Tabs>
  );
}

const styles = StyleSheet.create({
  tabBar: {
    position: 'absolute',
    bottom: 0,
    left: 0,
    right: 0,
    overflow: 'hidden',
  },
  blurBase: {
    borderTopLeftRadius: 0,
    borderTopRightRadius: 0,
  },
  androidBase: {
    backgroundColor: '#FFFFFF',
    borderTopWidth: 1,
    borderTopColor: '#F1F5F9',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: -4 },
    shadowOpacity: 0.06,
    shadowRadius: 12,
    elevation: 12,
  },
  topBorderLine: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    height: 1,
    backgroundColor: 'rgba(241,245,249,0.9)',
  },
  pillContainer: {
    position: 'absolute',
    top: 6,
    left: 0,
    width: TAB_WIDTH,
    alignItems: 'center',
    pointerEvents: 'none',
  },
  pill: {
    width: TAB_WIDTH * 0.55,
    height: 3,
    borderRadius: 2,
    backgroundColor: Colors.primary,
  },
  tabsRow: {
    flexDirection: 'row',
    alignItems: 'flex-end',
    paddingTop: 10,
  },
  tabItem: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
    gap: 3,
    paddingBottom: 4,
  },
  tabLabel: {
    fontSize: 10,
    fontFamily: Typography.fontFamily,
    letterSpacing: 0.1,
  },
  tabLabelActive: {
    fontFamily: Typography.fontFamilySemiBold,
  },
});

