      </GestureHandlerRootView>
    </PersistQueryClientProvider>
  );
}

import React, { useEffect, useState } from 'react';
import { View, Text, StyleSheet, Dimensions, type DimensionValue } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  useAnimatedProps,
  withTiming,
  withSequence,
  withRepeat,
  withDelay,
  Easing,
  type SharedValue,
} from 'react-native-reanimated';
