                    <View style={styles.metaRow}>
                      <Text style={styles.metaText}>{formatDateTime(item.createdAt)}</Text>
                      {showStaff && item.staff ? (
                        <>
                          <Text style={styles.metaDot}>·</Text>
                          <Text style={styles.metaText}>{item.staff.name}</Text>
