                      ) : null}
                    </View>
                  </View>

                  {/* Right side */}
                  <View style={styles.right}>
                    <Text style={styles.amount}>{formatCurrency(item.totalAmount)}</Text>
                    <View style={[styles.paymentBadge, { backgroundColor: payment.bg }]}>
                      <Ionicons name={payment.icon} size={10} color={payment.color} />
