import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { AnimatedPressable } from '@/components/ui/AnimatedPressable';
import { useAlert } from '@/context/AlertContext';
import { Input } from '../ui/Input';
import { Button } from '../ui/Button';
import { BottomSheet } from '../ui/BottomSheet';
import { Colors } from '@/constants/Colors';
import { Typography } from '@/constants/Typography';
import { Spacing } from '@/constants/Spacing';
import { BorderRadius } from '@/constants/BorderRadius';
import { formatCurrency } from '@/utils/formatters';
import type { ProductVariant } from '@/services/products';

interface VariantPickerModalProps {
  visible: boolean;
  onClose: () => void;
  onConfirm: (variant: ProductVariant, quantity: number) => void;
  productName: string;
  variants: ProductVariant[];
  loading?: boolean;
}

export const VariantPickerModal: React.FC<VariantPickerModalProps> = ({
  visible,
  onClose,
  onConfirm,
  productName,
  variants,
  loading = false,
}) => {
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [quantity, setQuantity] = useState('1');
  const { toast } = useAlert();

  useEffect(() => {
    if (visible) {
      setSelectedId(variants.find((v) => v.quantity > 0)?._id ?? variants[0]?._id ?? null);
      setQuantity('1');
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visible]);

  const selected = variants.find((v) => v._id === selectedId);

  const handleConfirm = () => {
    if (!selected) {
      toast({ type: 'warning', message: 'Please choose a variant before adding to cart' });
      return;
    }
    const qty = parseInt(quantity, 10);
    if (isNaN(qty) || qty <= 0 || qty > selected.quantity) {
      toast({ type: 'error', message: `Quantity must be between 1 and ${selected.quantity}` });
      return;
    }
    onConfirm(selected, qty);
  };

  return (
    <BottomSheet visible={visible} onClose={onClose}>
      <Text style={styles.title}>Choose an Option</Text>
      <Text style={styles.productName}>{productName}</Text>

      <View style={styles.chipRow}>
        {variants.map((v) => {
          const active = v._id === selectedId;
          const outOfStock = v.quantity === 0;
          return (
            <AnimatedPressable
              key={v._id}
              style={[styles.chip, active && styles.chipActive, outOfStock && styles.chipDisabled]}
              onPress={() => !outOfStock && setSelectedId(v._id)}
              disabled={outOfStock}
            >
              <Text style={[styles.chipText, active && styles.chipTextActive]}>{v.name}</Text>
              <Text style={[styles.chipPrice, active && styles.chipTextActive]}>
                {formatCurrency(v.sellingPrice)}{outOfStock ? ' · Out of stock' : ''}
              </Text>
            </AnimatedPressable>
          );
        })}
      </View>

      {selected && (
        <>
          <Text style={styles.maxStock}>Available: {selected.quantity}</Text>
          <Input label="Quantity" value={quantity} onChangeText={setQuantity} keyboardType="numeric" />
        </>
      )}

      <View style={styles.buttonRow}>
        <Button title="Cancel" variant="outline" onPress={onClose} style={styles.flexBtn} />
        <Button title="Add" onPress={handleConfirm} loading={loading} style={styles.flexBtn} />
      </View>
    </BottomSheet>
  );
};

const styles = StyleSheet.create({
  title: { fontSize: Typography.size.h3, fontFamily: Typography.fontFamilyBold, marginBottom: Spacing.sm, textAlign: 'center', color: Colors.textPrimary },
  productName: { fontSize: Typography.size.body, textAlign: 'center', marginBottom: Spacing.md },
  chipRow: { flexDirection: 'row', flexWrap: 'wrap', gap: Spacing.sm, marginBottom: Spacing.md },
  chip: { paddingHorizontal: Spacing.md, paddingVertical: Spacing.sm, borderRadius: BorderRadius.md, borderWidth: 1, borderColor: Colors.border, minWidth: 100 },
  chipActive: { backgroundColor: Colors.primary, borderColor: Colors.primary },
  chipDisabled: { opacity: 0.4 },
  chipText: { fontSize: Typography.size.small, fontFamily: Typography.fontFamilySemiBold, color: Colors.textPrimary },
  chipPrice: { fontSize: Typography.size.caption, color: Colors.textSecondary, marginTop: 2 },
  chipTextActive: { color: Colors.white },
  maxStock: { fontSize: Typography.size.small, textAlign: 'center', color: Colors.textSecondary, marginBottom: Spacing.sm },
  buttonRow: { flexDirection: 'row', gap: Spacing.md, marginTop: Spacing.md },
  flexBtn: { flex: 1 },
});

import React, { useEffect, useState } from 'react';
import { View, Text, StyleSheet, ActivityIndicator } from 'react-native';
import Animated, {
  FadeInDown,
  useSharedValue,
  useAnimatedStyle,
  withRepeat,
  withSequence,
  withTiming,
  Easing,
} from 'react-native-reanimated';
import Ionicons from '@expo/vector-icons/Ionicons';
import { AnimatedPressable } from '@/components/ui/AnimatedPressable';
import { StartShiftSheet } from './StartShiftSheet';
import { EndShiftSheet } from './EndShiftSheet';
import { useShift } from '@/hooks/useShift';
import { formatCurrency } from '@/utils/formatters';
import { haptics } from '@/utils/haptics';
import { Colors } from '@/constants/Colors';
import { Typography } from '@/constants/Typography';
import { Spacing } from '@/constants/Spacing';
import { BorderRadius } from '@/constants/BorderRadius';
import { Shadows } from '@/constants/Shadows';

const useShiftClock = (startedAt?: string) => {
  const [elapsed, setElapsed] = useState('');
  useEffect(() => {
    if (!startedAt) return;
    const compute = () => {
      const mins = Math.max(0, Math.floor((Date.now() - new Date(startedAt).getTime()) / 60000));
      setElapsed(mins < 60 ? `${mins}m` : `${Math.floor(mins / 60)}h ${mins % 60}m`);
    };
    // First tick via macrotask (not synchronously in the effect body) so the
    // render that mounted the bar isn't immediately followed by a cascade.
    const kickoff = setTimeout(compute, 0);
    const id = setInterval(compute, 30_000);
    return () => {
      clearTimeout(kickoff);
      clearInterval(id);
    };
  }, [startedAt]);
  return startedAt ? elapsed : '';
};

/** Slim status strip shown above the till while a shift is running. */
export const ActiveShiftBar: React.FC = () => {
  const { enabled, shift } = useShift();
  const [ending, setEnding] = useState(false);
  const elapsed = useShiftClock(shift?.startedAt);

  const pulse = useSharedValue(1);
  useEffect(() => {
    pulse.value = withRepeat(
      withSequence(
        withTiming(0.35, { duration: 900, easing: Easing.inOut(Easing.ease) }),
        withTiming(1, { duration: 900, easing: Easing.inOut(Easing.ease) })
      ),
      -1
    );
  }, []);
  const dotStyle = useAnimatedStyle(() => ({ opacity: pulse.value }));

  if (!enabled || !shift) return null;

  return (
    <>
      <Animated.View entering={FadeInDown.duration(300)} style={styles.bar}>
        <Animated.View style={[styles.dot, dotStyle]} />
        <Text style={styles.barText}>
          On shift{elapsed ? ` · ${elapsed}` : ''} · float {formatCurrency(shift.openingFloat)}
        </Text>
        <AnimatedPressable
          onPress={() => {
            haptics.light();
            setEnding(true);
          }}
          style={styles.endBtn}
          accessibilityRole="button"
          accessibilityLabel="End shift"
        >
          <Text style={styles.endBtnText}>End shift</Text>
        </AnimatedPressable>
      </Animated.View>
      <EndShiftSheet visible={ending} shift={shift} onClose={() => setEnding(false)} />
    </>
  );
};

interface ShiftGateProps {
  children: React.ReactNode;
}

/**
 * Wraps the staff till: when the shop enforces shift management and no shift
 * is open, selling is locked behind a "start your shift" takeover. Everything
 * else (feature off, shift running, still loading with cached data) renders
 * the till as normal.
 */
export const ShiftGate: React.FC<ShiftGateProps> = ({ children }) => {
  const { enabled, shift, isLoading } = useShift();
  const [starting, setStarting] = useState(false);

  if (isLoading) {
    return (
      <View style={styles.loading}>
        <ActivityIndicator color={Colors.primary} />
      </View>
    );
  }

  if (!enabled || shift) return <>{children}</>;

  return (
    <View style={styles.gate}>
      <Animated.View entering={FadeInDown.duration(450)} style={styles.gateIcon}>
        <Ionicons name="storefront-outline" size={40} color={Colors.primary} />
      </Animated.View>
      <Animated.Text entering={FadeInDown.duration(450).delay(80)} style={styles.gateTitle}>
        Ready to sell?
      </Animated.Text>
      <Animated.Text entering={FadeInDown.duration(450).delay(160)} style={styles.gateSub}>
        Start your shift to unlock the till. Count the drawer, clock in, and every sale you make
        will reconcile automatically when you clock out.
      </Animated.Text>
      <Animated.View entering={FadeInDown.duration(450).delay(240)} style={styles.gateCtaWrap}>
        <AnimatedPressable
          onPress={() => {
            haptics.medium();
            setStarting(true);
          }}
          style={styles.gateCta}
          accessibilityRole="button"
          accessibilityLabel="Start shift"
        >
          <Ionicons name="play" size={18} color="#FFFFFF" />
          <Text style={styles.gateCtaText}>Start Shift</Text>
        </AnimatedPressable>
      </Animated.View>

      <StartShiftSheet visible={starting} onClose={() => setStarting(false)} />
    </View>
  );
};

const styles = StyleSheet.create({
  loading: { flex: 1, alignItems: 'center', justifyContent: 'center' },
  bar: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 8,
    backgroundColor: '#0F172A',
    borderRadius: BorderRadius.lg,
    marginHorizontal: Spacing.md,
    marginBottom: Spacing.sm,
    paddingVertical: 8,
    paddingLeft: Spacing.md,
    paddingRight: 8,
  },
  dot: { width: 8, height: 8, borderRadius: 4, backgroundColor: '#34D399' },
  barText: {
    flex: 1,
    color: 'rgba(248,250,252,0.85)',
    fontSize: Typography.size.caption,
    fontFamily: Typography.fontFamilySemiBold,
    fontVariant: ['tabular-nums'],
  },
  endBtn: {
    backgroundColor: 'rgba(255,255,255,0.12)',
    borderRadius: BorderRadius.md,
