import React, { useEffect, useRef, useState } from 'react';
import { Text, View, StyleSheet } from 'react-native';
import { AnimatedPressable } from './AnimatedPressable';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withTiming,
  withSequence,
  Easing,
  SlideInUp,
  SlideOutUp,
} from 'react-native-reanimated';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import NetInfo from '@react-native-community/netinfo';
import Ionicons from '@expo/vector-icons/Ionicons';
import { onQueueCountChange, onSyncStateChange, getPendingCount } from '@/utils/offlineQueue';
import { Typography } from '@/constants/Typography';
import { Spacing } from '@/constants/Spacing';

// ─── Colour tokens ─────────────────────────────────────────────────────────────

const OFFLINE_BG   = '#F97316'; // warm orange
const SYNCING_BG   = '#0F766E'; // teal
const DONE_BG      = '#15803D'; // green — brief "all synced" flash
const PILL_TEXT    = '#FFFFFF';

// ─── Pulsing dot for "syncing" state ──────────────────────────────────────────

const PulsingDot: React.FC = () => {
  const opacity = useSharedValue(1);

  useEffect(() => {
    const pulse = () => {
      opacity.value = withSequence(
        withTiming(0.3, { duration: 500, easing: Easing.inOut(Easing.ease) }),
        withTiming(1,   { duration: 500, easing: Easing.inOut(Easing.ease) }),
      );
    };
    pulse();
    const id = setInterval(pulse, 1000);
    return () => clearInterval(id);
  }, []);

  const style = useAnimatedStyle(() => ({ opacity: opacity.value }));

  return <Animated.View style={[dot.base, style]} />;
};

const dot = StyleSheet.create({
  base: {
    width: 7,
    height: 7,
    borderRadius: 3.5,
    backgroundColor: PILL_TEXT,
    marginRight: 7,
  },
});

// ─── State machine ─────────────────────────────────────────────────────────────

type ToastPhase = 'offline' | 'syncing' | 'done' | 'hidden';

// ─── Main component ────────────────────────────────────────────────────────────

export const OfflineIndicator: React.FC = () => {
  const [online, setOnline]           = useState(true);
  const [pendingCount, setPendingCount] = useState(0);
  const [syncing, setSyncing]         = useState(false);
  const [phase, setPhase]             = useState<ToastPhase>('hidden');

  const insets = useSafeAreaInsets();

  // Refs used to drive auto-dismiss timers without stale closures
  const dismissTimerRef  = useRef<ReturnType<typeof setTimeout> | null>(null);
  const doneTimerRef     = useRef<ReturnType<typeof setTimeout> | null>(null);
  const prevPendingRef   = useRef<number>(0);

  const clearDismiss = () => {
    if (dismissTimerRef.current) { clearTimeout(dismissTimerRef.current); dismissTimerRef.current = null; }
  };
  const clearDone = () => {
    if (doneTimerRef.current) { clearTimeout(doneTimerRef.current); doneTimerRef.current = null; }
  };

  // Subscribe to reactive data sources
  useEffect(() => {
    const initial = getPendingCount();
    setPendingCount(initial);
    // Seed the ref so the "queue just drained" logic works on the very first sync
    prevPendingRef.current = initial;

    const unsubNet   = NetInfo.addEventListener(s => setOnline(!!s.isConnected));
    const unsubCount = onQueueCountChange(count => {
      setPendingCount(count);
      prevPendingRef.current = count;
    });
    const unsubSync  = onSyncStateChange(setSyncing);

    NetInfo.fetch().then(s => setOnline(!!s.isConnected));

    return () => { unsubNet(); unsubCount(); unsubSync(); };
  }, []);

  // Drive the phase state machine
  useEffect(() => {
    clearDismiss();
    clearDone();

    if (!online) {
      // Offline: show orange toast, auto-dismiss after 6 s
      setPhase('offline');
      dismissTimerRef.current = setTimeout(() => setPhase('hidden'), 6000);
      return;
    }

    if (syncing || pendingCount > 0) {
      // Online + syncing: show teal toast, no auto-dismiss (wait for queue drain)
      setPhase('syncing');
      return;
    }

    if (prevPendingRef.current > 0 && pendingCount === 0) {
      // Queue just drained: flash green "Synced" for 2 s then hide
      setPhase('done');
      doneTimerRef.current = setTimeout(() => setPhase('hidden'), 2000);
      return;
    }

    // All clear
    setPhase('hidden');
  }, [online, syncing, pendingCount]);

  // Cleanup on unmount
  useEffect(() => () => { clearDismiss(); clearDone(); }, []);

  if (phase === 'hidden') return null;

  const bg = phase === 'offline' ? OFFLINE_BG : phase === 'done' ? DONE_BG : SYNCING_BG;

  const label =
    phase === 'offline'
      ? `No internet${pendingCount > 0 ? ` · ${pendingCount} pending` : ''}`
      : phase === 'done'
        ? 'All synced'
        : `Syncing${pendingCount > 0 ? ` ${pendingCount} item${pendingCount > 1 ? 's' : ''}` : ''}…`;

  const iconName: keyof typeof Ionicons.glyphMap =
    phase === 'offline' ? 'cloud-offline-outline' : phase === 'done' ? 'checkmark-circle-outline' : 'sync-outline';

  return (
    <Animated.View
      entering={SlideInUp.springify().damping(18).stiffness(200)}
      exiting={SlideOutUp.duration(220)}
      style={[styles.wrapper, { top: insets.top + 10 }]}
      pointerEvents="box-none"
    >
      <View style={[styles.pill, { backgroundColor: bg }]}>
        {phase === 'syncing' ? (
          <PulsingDot />
        ) : (
          <Ionicons name={iconName} size={14} color={PILL_TEXT} style={styles.icon} />
        )}
        <Text style={styles.label} numberOfLines={1}>{label}</Text>

        {/* Close button — lets user dismiss the toast early */}
        {phase !== 'done' && (
          <AnimatedPressable
            onPress={() => setPhase('hidden')}
            hitSlop={{ top: 10, bottom: 10, left: 10, right: 10 }}
            style={styles.close}
          >
            <Ionicons name="close" size={14} color="rgba(255,255,255,0.75)" />
          </AnimatedPressable>
        )}
      </View>
    </Animated.View>
  );
};

// ─── Styles ───────────────────────────────────────────────────────────────────

const styles = StyleSheet.create({
  wrapper: {
    position: 'absolute',
    left: 0,
    right: 0,
    zIndex: 9999,
    elevation: 14,
    alignItems: 'center',
    pointerEvents: 'box-none',
  },
  pill: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 16,
    paddingVertical: 9,
    borderRadius: 40,
    // Shadow
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.25,
    shadowRadius: 10,
    elevation: 14,
    // Max width so it reads like a toast, not a banner
    maxWidth: 320,
  },
  icon: {
    marginRight: 7,
  },
  label: {
    flex: 1,
    color: PILL_TEXT,
    fontSize: Typography.size.caption,
    fontFamily: Typography.fontFamilySemiBold,
    letterSpacing: 0.2,
  },
  close: {
    marginLeft: 8,
    opacity: 0.85,
  },
});

import React, { createContext, useContext, useEffect } from 'react';
import { router } from 'expo-router';
import axios from 'axios';
import * as Haptics from 'expo-haptics';
import { useAuthStore } from '@/store/authStore';
import { login as loginApi, getProfile } from '@/services/auth';
import { API_BASE_URL } from '@/constants/config';
import { clearAll } from '@/utils/storage';
import { waitForHydration } from '@/utils/hydration';
import {
  registerDeviceForNotifications,
  unregisterDeviceFromNotifications,
  getNotificationsPreference,
} from '@/services/notifications';

interface AuthContextType {
  user: ReturnType<typeof useAuthStore.getState>['user'];
  isLoading: boolean;
  isAuthenticated: boolean;
  login: (email: string, password: string) => Promise<{
    success: boolean;
    message?: string;
    role?: 'owner' | 'staff';
    needsVerification?: boolean;
  }>;
  logout: () => Promise<void>;
  refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

// Module-level flag prevents the logout side-effects (token clear, navigation)
// from firing twice when both SessionExpiredHandler's timer and a route guard
// call logout() in the same tick.
let logoutInProgress = false;

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user, setAuth, logout: storeLogout, isLoading, setLoading } = useAuthStore();

  useEffect(() => {
    const initAuth = async () => {
      try {
        // SecureStore hydration is async — reading the store before it lands
        // sees a null user, skips the profile/FCM refresh, and flips
        // isLoading off while a real session is still on its way in.
        await waitForHydration(useAuthStore);
        const storedUser = useAuthStore.getState().user;
        if (storedUser) {
          await getProfile();
          // Re-registers this device's FCM token on every app start (not
          // just at login) — otherwise a token that rotated or never made
          // it to the backend (e.g. permission granted after first login)
          // stays out of sync until the user manually logs out/in again.
          if (storedUser.role === 'owner' && (await getNotificationsPreference())) {
            registerDeviceForNotifications();
          }
        }
      } catch (error: any) {
        // Only clear the session when the server explicitly rejected it.
        // A network failure here just means the app started offline — the
        // cached session must survive, or offline-first is dead on arrival
        // (the login screen can't authenticate without a connection).
        if (error?.response?.status === 401) {
          await clearAll();
          storeLogout();
        }
      } finally {
        setLoading(false);
      }
    };
    initAuth();
  }, []);

  const login = async (email: string, password: string) => {
    try {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
      const response = await loginApi(email, password);
      if (response.success) {
        const { token, refreshToken, ...userData } = response.data;
        setAuth(userData, token, refreshToken);
        // Only owners receive sales-anomaly/low-stock pushes — skip the
        // permission prompt for staff, who'd never get a notification.
        // Also respect a previously-saved "notifications off" preference.
        if (userData.role === 'owner' && (await getNotificationsPreference())) {
          registerDeviceForNotifications();
        }
        return { success: true, role: userData.role };
      }
      return { success: false, message: response.message };
    } catch (error: any) {
      const message = error.response?.data?.message || 'Login failed';
      const needsVerification = error.response?.status === 401 && /verify your email/i.test(message);
      return { success: false, message, needsVerification };
    }
  };

  const logout = async () => {
    if (logoutInProgress) return;
    logoutInProgress = true;
    try {
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Warning);
      // Best-effort server-side revocation of the refresh token (raw axios:
      // must not be queued offline, and needs no auth header). Fire and
      // forget — logout must never hang on a dead connection.
      const { refreshToken } = useAuthStore.getState();
      if (refreshToken) {
        axios
          .post(`${API_BASE_URL}/auth/logout`, { refreshToken }, { timeout: 5000 })
          .catch(() => {});
      }
      // Must run before clearAll/storeLogout — it needs the still-valid auth token.
      await unregisterDeviceFromNotifications();
      await clearAll();
      storeLogout();
      router.replace('/(auth)/login');
    } finally {
      // Reset after navigation settles so a fresh login can log out again.
      setTimeout(() => { logoutInProgress = false; }, 2000);
    }
  };

  const refreshUser = async () => {
    try {
      const profile = await getProfile();
      if (profile.success) {
        const currentToken = useAuthStore.getState().token;
        setAuth(profile.data as any, currentToken!);
      }
    } catch {
      if (__DEV__) console.error('Failed to refresh user profile');
    }
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isLoading,
        isAuthenticated: !!user,
        login,
        logout,
        refreshUser,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

