import api from './api';

export interface OwnerDashboardData {
  todaySalesTotal: number;
  cashSalesTotal: number;
  mpesaSalesTotal: number;
  transactionsToday: number;
  totalProducts: number;
  currentStockValue: number;
  lowStockItems: Array<{
    _id: string;
    name: string;
    quantity: number;
    lowStockAlert: number;
  }>;
  recentTransactions: Array<{
    _id: string;
    invoiceNumber: string;
    totalAmount: number;
    paymentMethod: string;
    createdAt: string;
    staff: { name: string };
  }>;
  ratingSummary: {
    avgStars: number;
    totalRatings: number;
  };
}

export interface StaffDashboardData {
  todaySalesTotal: number;
  cashSalesTotal: number;
  mpesaSalesTotal: number;
  transactionsToday: number;
  recentSales: Array<{
    _id: string;
    invoiceNumber: string;
    totalAmount: number;
    paymentMethod: string;
    createdAt: string;
  }>;
}

interface ApiResponse<T> {
  success: boolean;
  data: T;
  message?: string;
}

/**
 * Get owner dashboard data
 * Requires owner role
 */
export const getOwnerDashboard = async (): Promise<ApiResponse<OwnerDashboardData>> => {
  const response = await api.get('/dashboard/owner');
  return response.data;
};

/**
 * Get staff dashboard data
 * Staff sees only their own performance
 */
export const getStaffDashboard = async (): Promise<ApiResponse<StaffDashboardData>> => {
  const response = await api.get('/dashboard/staff');
  return response.data;
};

import api from './api';

export interface Rating {
  _id: string;
  shop: string;
  sale: { _id: string; invoiceNumber: string; totalAmount: number; createdAt: string } | string;
  staff: { _id: string; name: string } | string;
  stars: number;
  comment?: string;
  createdAt: string;
}

export interface RatingsResponse {
  success: boolean;
  data: Rating[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    pages: number;
  };
}

export interface RatingsSummary {
  avgStars: number;
  totalRatings: number;
  distribution: Array<{ stars: number; count: number }>;
  byStaff: Array<{ staffId: string; staffName: string; avgStars: number; totalRatings: number }>;
}

export interface RatingsSummaryResponse {
  success: boolean;
  data: RatingsSummary;
}

export interface PublicReceipt {
  invoiceNumber: string;
  shopName: string;
  currency: string;
  totalAmount: number;
  itemCount: number;
  createdAt: string;
  alreadyRated: boolean;
  rating: { stars: number; comment?: string } | null;
}

export interface PublicReceiptResponse {
  success: boolean;
  data: PublicReceipt;
  message?: string;
}

/**
 * Get ratings list (Owner only)
 */
export const getRatings = async (params?: {
  staffId?: string;
  stars?: number;
  page?: number;
  limit?: number;
}): Promise<RatingsResponse> => {
  const response = await api.get('/ratings', { params });
  return response.data;
};

/**
 * Get ratings summary — averages, distribution, per-staff breakdown (Owner only)
 */
export const getRatingsSummary = async (): Promise<RatingsSummaryResponse> => {
  const response = await api.get('/ratings/summary');
  return response.data;
};

/**
 * Fetch a receipt for public verification by its QR token (no auth)
 */
export const getPublicReceipt = async (token: string): Promise<PublicReceiptResponse> => {
  const response = await api.get(`/public/receipt/${token}`);
  return response.data;
};

/**
 * Submit a customer rating for a receipt by its QR token (no auth)
 */
export const submitPublicRating = async (
  token: string,
  data: { stars: number; comment?: string }
): Promise<{ success: boolean; data: Rating; message?: string }> => {
  const response = await api.post(`/public/receipt/${token}/rating`, data);
  return response.data;
};

